// Find the uploaded image binary and build the full Anthropic request body.
// IMPORTANT: on n8n Cloud, binary.data is a filesystem pointer (e.g. 'filesystem-v2'),
// NOT the actual base64. We must call getBinaryDataBuffer to read the real bytes.
const item = items[0];
const binaries = item.binary || {};
const keys = Object.keys(binaries);
if (keys.length === 0) {
  throw new Error('No binary file received. Available keys: ' + JSON.stringify(Object.keys(item)));
}
const key = binaries.pdfFile ? 'pdfFile' : keys[0];
const binary = binaries[key];
const buffer = await this.helpers.getBinaryDataBuffer(0, key);
const base64 = buffer.toString('base64');
const mime = binary.mimeType || 'image/jpeg';

const prompt = `You are a college financial aid analyst. Analyze this award letter image.

STEP 1 — EXTRACT EVERY LINE. Read every dollar amount on the page, including additional financing options at the bottom. Don't drop any line.

STEP 2 — BUCKET COST OF ATTENDANCE LINES.

direct_costs.tuition: "Tuition" or bundled "Tuition & Fees".
direct_costs.housing: SUM of Room + Board + Meals + Dining + Food + Living Allowance. Always include board/meals — don't restrict to room only.
direct_costs.fees: Mandatory Fees, Lab Fees, Health Insurance, Residential College Fee, Enrollment Fees.

Books, Personal Expenses, Transportation, Travel count toward total_cost_of_attendance but NOT direct_costs.

total_cost_of_attendance = sum of EVERY COA line (direct + indirect).

STEP 3 — BUCKET AID LINES.

GIFT AID (free money — never repaid). Sub-buckets:
- pell_grant: lines containing "Pell" or "Federal Pell".
- state_grant: any grant administered by a state government, even when "state" is not in the name. Examples: Cal Grant A, Cal Grant B, CA College Promise Grant, Texas Grant, NJ Tuition Aid Grant, MA State Grant, Florida Bright Futures.
- institutional_merit: scholarships funded by the school. Examples: school name in title (UC Grant, Pomona College Grant, Berklee Achievement Scholarship), Athletic Grant-in-Aid, Heritage Scholarship, Go Blue Guarantee Grant, Presidential Scholarship.

LOANS (debt — must be repaid). Sub-buckets:
- federal_subsidized: "Federal Direct Subsidized".
- federal_unsubsidized: "Federal Direct Unsubsidized" — DO NOT drop if listed.
- parent_plus: "Parent PLUS" or "PLUS Loan" — extract even if listed under "Additional financing options".
- private_loans: any loan that isn't one of the above (Institutional Student Loan, alternative/private loans).

WORK-STUDY (earned — student must work):
- work_study: any line containing Work-Study, Work Study, FWS, Federal Work-Study, or Student Campus Job. Always extract — do not omit.

STEP 4 — CALCULATE:
- total_gift_aid = pell_grant + state_grant + institutional_merit (the breakdown MUST sum to total_gift_aid).
- net_price = total_cost_of_attendance − total_gift_aid (never negative).
- out_of_pocket_payment = net_price (loans are OPTIONAL debt).

STEP 5 — VERIFY before returning:
1. Does pell + state + institutional equal total_gift_aid? If not, you've miscategorized — re-bucket.
2. Did you include work_study and federal_unsubsidized if either is listed?
3. Does direct_costs.housing include board/meals/dining/food (not just room)?

STEP 6 — RETURN ONLY THIS JSON OBJECT (not an array, no markdown, no fences, no commentary):
{
  "college_name": "Name from letterhead",
  "total_cost_of_attendance": 0,
  "direct_costs": {"tuition": 0, "housing": 0, "fees": 0},
  "grants_scholarships": {"institutional_merit": 0, "pell_grant": 0, "state_grant": 0, "total_gift_aid": 0},
  "loans": {"federal_subsidized": 0, "federal_unsubsidized": 0, "parent_plus": 0, "private_loans": 0},
  "work_study": 0,
  "net_price": 0,
  "out_of_pocket_payment": 0,
  "analysis": {"debt_warning": "Low|Medium|High|Critical", "value_score": 0}
}

Debt warning rules:
- Low: loans < $5,000/yr, no Parent PLUS
- Medium: loans $5,000–10,000/yr
- High: loans > $10,000/yr OR net price > $30,000
- Critical: Parent PLUS present OR net price > $50,000

value_score is 0–100. Higher = better deal.

OUTPUT THE JSON OBJECT ONLY.`;

const strictPrompt = `You are a college financial aid analyst. The previous attempt produced invalid JSON. Be EXTRA strict.

Return ONLY a single JSON object — no markdown, no code fences, no prose, no array wrapper.

Schema (all numbers required, use 0 if unknown):
{
  "college_name": string,
  "total_cost_of_attendance": number,
  "direct_costs": {"tuition": number, "housing": number, "fees": number},
  "grants_scholarships": {"institutional_merit": number, "pell_grant": number, "state_grant": number, "total_gift_aid": number},
  "loans": {"federal_subsidized": number, "federal_unsubsidized": number, "parent_plus": number, "private_loans": number},
  "work_study": number,
  "net_price": number,
  "out_of_pocket_payment": number,
  "analysis": {"debt_warning": "Low" | "Medium" | "High" | "Critical", "value_score": number}
}

Rules:
- total_gift_aid = ONLY grants + scholarships (no loans, no work-study)
- pell_grant + state_grant + institutional_merit MUST equal total_gift_aid
- direct_costs.housing must include Room + Board + Meals + Dining + Food
- state_grant includes state-administered grants like Cal Grant or CA College Promise Grant even if "state" is not in the name
- Always extract work_study and federal_unsubsidized if listed; do not drop them
- net_price = total_cost_of_attendance − total_gift_aid (never negative)
- debt_warning: Low <$5k loans/no PLUS, Medium $5–10k, High >$10k or net>$30k, Critical PLUS or net>$50k
- value_score: 0–100, higher = better deal

OUTPUT THE JSON OBJECT ONLY. NO OTHER TEXT.`;

const makeBody = (model, text) => ({
  model,
  max_tokens: 2048,
  messages: [{
    role: 'user',
    content: [
      { type: 'image', source: { type: 'base64', media_type: mime, data: base64 } },
      { type: 'text', text }
    ]
  }]
});

return [{
  json: {
    haikuBody: makeBody('claude-haiku-4-5-20251001', prompt),
    sonnetBody: makeBody('claude-sonnet-4-6', strictPrompt),
    fileName: binary.fileName || 'unknown'
  }
}];

// Validate Claude's response. Strip markdown fences, parse JSON, check shape.
const response = items[0].json;
const raw = response?.content?.[0]?.text ?? '';

function clean(text) {
  let t = String(text).trim();
  t = t.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  const first = t.search(/[\[{]/);
  const last = Math.max(t.lastIndexOf(']'), t.lastIndexOf('}'));
  if (first !== -1 && last > first) t = t.substring(first, last + 1);
  return t.replace(/,\s*([\]}])/g, '$1');
}

try {
  const cleaned = clean(raw);
  const parsed = JSON.parse(cleaned);
  // Unwrap single-element array if Claude returned one despite instructions.
  const obj = Array.isArray(parsed) ? parsed[0] : parsed;
  // Minimal shape check; full Zod validation happens in Next.js.
  const ok = obj
    && typeof obj.college_name === 'string'
    && typeof obj.net_price === 'number'
    && typeof obj.total_cost_of_attendance === 'number'
    && obj.analysis && typeof obj.analysis.debt_warning === 'string';
  if (!ok) return [{ json: { valid: false, raw, reason: 'shape_check_failed' } }];
  return [{ json: { valid: true, data: obj } }];
} catch (e) {
  return [{ json: { valid: false, raw, reason: 'parse_error: ' + e.message } }];
}

